-- // modules/utils.lua
do
Utils = {}

function Utils.waitForCharacter(player)
    local character = player.Character or player.CharacterAdded:Wait()
    local humanoid = character:WaitForChild("Humanoid", 10)
    local head = character:WaitForChild("Head", 10)
    
    if humanoid and head then
        return character, humanoid, head
    end
    return nil
end

function Utils.getNeckJoint(character, humanoid)
    if humanoid.RigType == Enum.HumanoidRigType.R6 then
        local torso = character:WaitForChild("Torso", 5)
        if torso then
            return torso:WaitForChild("Neck", 5)
        end
    elseif humanoid.RigType == Enum.HumanoidRigType.R15 then
        local head = character:WaitForChild("Head", 5)
        if head then
            return head:WaitForChild("Neck", 5)
        end
    end
    return character:FindFirstChild("Neck", true)
end



end

-- // modules/headless.lua
do
local RunService = game:GetService("RunService")
-- local Utils
-- local Config

Headless = {
    Connections = {},
    OriginalC0 = nil,
    Active = false
}

function Headless.Enable(player)
    if Headless.Active then return end
    Headless.Active = true
    
    local function applyHeadless(character)
        local _, humanoid, head = Utils.waitForCharacter(player)
        if not character or not humanoid or not head then return end
        
        local neck = Utils.getNeckJoint(character, humanoid)
        if not neck then return end
        
        if not Headless.OriginalC0 then
            Headless.OriginalC0 = neck.C0
        end
        
        -- Vòng lặp giữ khớp cổ và tắt va chạm của đầu
        local connection
        connection = RunService.Heartbeat:Connect(function()
            if not neck or not neck.Parent or not head or not head.Parent then
                connection:Disconnect()
                return
            end
            if Headless.Active then
                -- Triệt tiêu vật lý của đầu để tránh kẹt đất/fling
                head.CanCollide = false
                head.Massless = true
                neck.C0 = Headless.OriginalC0 * CFrame.new(0, Config.Depth, 0)
            else
                neck.C0 = Headless.OriginalC0
                head.Massless = false
                connection:Disconnect()
            end
        end)
        table.insert(Headless.Connections, connection)
    end
    
    if player.Character then
        task.spawn(applyHeadless, player.Character)
    end
    
    local charAddedConn = player.CharacterAdded:Connect(function(character)
        task.wait(0.5)
        applyHeadless(character)
    end)
    table.insert(Headless.Connections, charAddedConn)
end

function Headless.Disable(player)
    Headless.Active = false
    
    for _, conn in ipairs(Headless.Connections) do
        if conn then
            conn:Disconnect()
        end
    end
    Headless.Connections = {}
    
    local character = player.Character
    if character then
        local humanoid = character:FindFirstChildOfClass("Humanoid")
        local head = character:FindFirstChild("Head")
        if head then
            head.Massless = false
        end
        if humanoid then
            local neck = Utils.getNeckJoint(character, humanoid)
            if neck and Headless.OriginalC0 then
                neck.C0 = Headless.OriginalC0
            end
        end
    end
    
    Headless.OriginalC0 = nil
end



end

